import { MeliStatsD } from '@meli/statsd';
import otel from 'node-melitk-otel/opentelemetry/api';
import { TRACE_EVENT_NAME, STAT_NAME } from '../constants.mjs';

const statsd = new MeliStatsD();
function notify(text, locale) {
    const activeSpan = otel.trace.getActiveSpan();
    const resolvedLocale = locale || 'unknown';
    activeSpan?.addEvent(TRACE_EVENT_NAME, {
        text,
        locale: resolvedLocale,
    });
    statsd.increment(STAT_NAME, { locale: resolvedLocale });
}

export { notify };
